__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"FRASES_DEPORTISTAS",{enumerable:!0,get:function(){return o}});const o=[{id:1,frase:'No compares tu cap\xedtulo 1 con el cap\xedtulo 20 de otro.',autor:'Simone Biles'},{id:2,frase:'No se trata de ser el mejor del mundo, sino de ser mejor que ayer.',autor:'Wayne Gretzky'},{id:3,frase:'He fallado una y otra vez, y por eso he tenido \xe9xito.',autor:'Michael Jordan'},{id:4,frase:'Ning\xfan ser humano est\xe1 limitado, solo la creencia lo est\xe1.',autor:'Eliud Kipchoge'},{id:5,frase:'La gloria est\xe1 en disfrutar el proceso, no solo en ganar.',autor:'Rafael Nadal'},{id:6,frase:'Ser el mejor todos los d\xedas importa m\xe1s que serlo una sola vez.',autor:'Tom Brady'},{id:7,frase:'Las cr\xedticas bien tomadas te hacen m\xe1s fuerte.',autor:'LeBron James'},{id:8,frase:'No dejes que nadie te diga que no puedes, ni siquiera t\xfa misma.',autor:'Serena Williams'},{id:9,frase:'Cada temporada es un nuevo reto que superar, no una meta cerrada.',autor:'Cristiano Ronaldo'},{id:10,frase:'Perder es parte del camino, pero detenerse nunca lo es.',autor:'Marta'},{id:11,frase:'La edad es una limitaci\xf3n que a veces solo existe en tu mente.',autor:'Jackie Joyner-Kersee'},{id:12,frase:'Celebra cada victoria, pero no te instales c\xf3modo en ella.',autor:'Mia Hamm'},{id:13,frase:'La consistencia diaria vale m\xe1s que el talento espont\xe1neo.',autor:'Roger Federer'},{id:14,frase:'Volver a competir despu\xe9s de perder tanto tambi\xe9n es ganar.',autor:'Bethany Hamilton'},{id:15,frase:'El coraje es intentarlo una vez m\xe1s al d\xeda siguiente.',autor:'Muhammad Ali'},{id:16,frase:'Tu mayor obst\xe1culo suele estar en tu propia mente.',autor:'Michael Phelps'},{id:17,frase:"Redefinir lo que significa 'estar en forma' tambi\xe9n es parte del progreso.",autor:'Allyson Felix'},{id:18,frase:'Un campe\xf3n le teme a perder; el resto le teme a ganar.',autor:'Billie Jean King'},{id:19,frase:'La presi\xf3n de competir no es una carga, es un privilegio.',autor:'Steffi Graf'},{id:20,frase:'Cree en ti misma justo cuando nadie m\xe1s lo hace.',autor:'Venus Williams'},{id:21,frase:'No dejes que nadie decida si eres suficiente, esa decisi\xf3n es tuya.',autor:'Serena Williams'},{id:22,frase:'Enorgull\xe9cete de cada paso, no solo del resultado final.',autor:'Simone Biles'},{id:23,frase:'Si le das a otros el poder de decirte que eres grande, tambi\xe9n les das el de decirte que no vales.',autor:'Ronda Rousey'},{id:24,frase:"Convierte cada 'no puedes' en tu motivaci\xf3n central.",autor:'Marta'},{id:25,frase:'La representaci\xf3n tambi\xe9n es parte del prop\xf3sito de competir.',autor:'Simone Manuel'},{id:26,frase:'Cuando la pasi\xf3n va primero, el resto se acomoda solo.',autor:'Holly Holm'},{id:27,frase:'Hazte responsable de tus victorias y tus derrotas por igual.',autor:'Maria Sharapova'},{id:28,frase:'Ocupar tu espacio con autenticidad tambi\xe9n es rendimiento.',autor:'Megan Rapinoe'},{id:29,frase:'T\xfa defines tu propio l\xedmite, no la comparaci\xf3n con otros.',autor:'Katie Ledecky'},{id:30,frase:'Aceptar el fracaso es parte del contrato con cualquier meta ambiciosa.',autor:'Michael Jordan'},{id:31,frase:'S\xe9 fiel a tu proceso incluso sin aplausos externos.',autor:'Kobe Bryant'},{id:32,frase:'El dolor entrenado con cabeza se convierte en fuerza, no en castigo.',autor:'Arnold Schwarzenegger'},{id:33,frase:'Transforma la ansiedad previa en ritual, no en enemigo.',autor:'Rafael Nadal'},{id:34,frase:'S\xe9 campeona por creer en ti, incluso sin respaldo externo.',autor:'Usain Bolt'},{id:35,frase:'La autoconfianza puede preceder al resultado.',autor:'Muhammad Ali'},{id:36,frase:'Separa tu valor personal del marcador de cada partido.',autor:'Alex Morgan'},{id:37,frase:'Disfrutar lo que haces importa m\xe1s que la sola obligaci\xf3n de ganar.',autor:'Pel\xe9'},{id:38,frase:'Tu historia de superaci\xf3n no te define como l\xedmite, sino como origen.',autor:'Jackie Joyner-Kersee'},{id:39,frase:'Ajustar la t\xe9cnica tambi\xe9n es una forma de no rendirse.',autor:'Bethany Hamilton'},{id:40,frase:'Escuchar tus l\xedmites reales tambi\xe9n es parte de competir bien.',autor:'Simone Biles'},{id:41,frase:'El rechazo temprano no define el techo de tu carrera.',autor:'Michael Jordan'},{id:42,frase:'Reconstruirte despu\xe9s de una lesi\xf3n grave tambi\xe9n es una victoria.',autor:'Kobe Bryant'},{id:43,frase:'Volver a pelear por lo tuyo despu\xe9s de perder a\xf1os enteros.',autor:'Muhammad Ali'},{id:44,frase:'Se puede competir de elite arrastrando dolor cr\xf3nico, con el manejo correcto.',autor:'Rafael Nadal'},{id:45,frase:'Exigir mejores condiciones tambi\xe9n es parte de cuidar tu carrera.',autor:'Allyson Felix'},{id:46,frase:'El rechazo inicial no impide construir un legado despu\xe9s.',autor:'Marta'},{id:47,frase:'Hablar de salud mental abiertamente tambi\xe9n es un logro deportivo.',autor:'Michael Phelps'},{id:48,frase:'Seguir compitiendo pese a una enfermedad cr\xf3nica autoinmune es una forma de fuerza.',autor:'Venus Williams'},{id:49,frase:'Adaptar el entrenamiento a tu cuerpo real vale m\xe1s que forzarlo.',autor:'Usain Bolt'},{id:50,frase:'Ser elegido de \xfaltimo no impide llegar a ser el mejor.',autor:'Tom Brady'},{id:51,frase:'La injusticia puede convertirse en motor de cambio, no solo en frustraci\xf3n.',autor:'Billie Jean King'},{id:52,frase:'Priorizar la recuperaci\xf3n por sobre el calendario tambi\xe9n es disciplina.',autor:'Simone Manuel'},{id:53,frase:'Aprender a perder correctamente es requisito para ganar despu\xe9s.',autor:'Kareem Abdul-Jabbar'},{id:54,frase:'El deporte tambi\xe9n puede ser el espacio donde canalizas el duelo.',autor:'Cristiano Ronaldo'},{id:55,frase:'Un intento fallido y p\xfablico no cancela el siguiente intento.',autor:'Eliud Kipchoge'},{id:56,frase:'Hablar de los pensamientos oscuros tambi\xe9n es parte de volver m\xe1s fuerte.',autor:'Ronda Rousey'},{id:57,frase:'Trabaja en silencio y deja que el resultado hable despu\xe9s.',autor:'Neymar Jr.'},{id:58,frase:'El h\xe1bito protegido incluso sin ganas es lo que sostiene el progreso.',autor:'Kobe Bryant'},{id:59,frase:'El talento gana partidos, la inteligencia colectiva gana campeonatos.',autor:'Michael Jordan'},{id:60,frase:'Trabaja hoy lo que otros evitan, para lograr ma\xf1ana lo que otros no pueden.',autor:'Jerry Rice'},{id:61,frase:'Entrenar sin pausas ni feriados tambi\xe9n construye al campe\xf3n.',autor:'Michael Phelps'},{id:62,frase:'El \xe9xito depende m\xe1s del m\xe9todo y la constancia que del talento puro.',autor:'Rafael Nadal'},{id:63,frase:'Una carrera larga se sostiene con recuperaci\xf3n tan disciplinada como el entrenamiento.',autor:'LeBron James'},{id:64,frase:'La pr\xe1ctica constante construye confianza, y la confianza te empodera.',autor:'Simone Biles'},{id:65,frase:'Sostener el mismo nivel de exigencia a los 20 y a los 39.',autor:'Cristiano Ronaldo'},{id:66,frase:'Quien no se arriesga lo suficiente no logra nada relevante.',autor:'Muhammad Ali'},{id:67,frase:'El \xe9xito de cada mujer debe inspirar al de la siguiente, no competir con \xe9l.',autor:'Serena Williams'},{id:68,frase:'La disciplina diaria pesa m\xe1s que el talento aislado.',autor:'Eliud Kipchoge'},{id:69,frase:'Perfeccionar un solo movimiento durante a\xf1os tambi\xe9n es maestr\xeda.',autor:'Kareem Abdul-Jabbar'},{id:70,frase:'Valora tus victorias, \xfasalas de impulso, nunca te instales en ellas.',autor:'Mia Hamm'},{id:71,frase:'Los campeones siguen intent\xe1ndolo hasta hacerlo bien.',autor:'Billie Jean King'},{id:72,frase:'Sostener el nivel f\xedsico casi dos d\xe9cadas es tambi\xe9n un logro silencioso.',autor:'Marta'},{id:73,frase:'La disciplina es la \xfanica condici\xf3n no negociable del \xe9xito sostenido.',autor:'Vince Lombardi'},{id:74,frase:'Ajustar alimentaci\xf3n y recuperaci\xf3n puede extender tu carrera m\xe1s de lo esperado.',autor:'Tom Brady'},{id:75,frase:'Priorizar la salud mental por sobre una medalla tambi\xe9n es una victoria.',autor:'Simone Biles'},{id:76,frase:'El m\xe1ximo rendimiento f\xedsico no exime del cuidado psicol\xf3gico.',autor:'Michael Phelps'},{id:77,frase:'Visibilizar riesgos m\xe9dicos poco escuchados tambi\xe9n es un aporte al deporte.',autor:'Serena Williams'},{id:78,frase:'Tu propia experiencia puede impulsar mejores pol\xedticas para las que vienen despu\xe9s.',autor:'Allyson Felix'},{id:79,frase:'Priorizar el sue\xf1o y la recuperaci\xf3n es tan entrenamiento como el esfuerzo explosivo.',autor:'Kobe Bryant'},{id:80,frase:'Adaptar la t\xe9cnica a una lesi\xf3n cr\xf3nica sin abandonar el nivel de elite.',autor:'Rafael Nadal'},{id:81,frase:'Escuchar al cuerpo es entrenamiento, no se\xf1al de debilidad.',autor:'Michael Jordan'},{id:82,frase:'Ajustar toda tu rutina ante un diagn\xf3stico, sin abandonar la competencia.',autor:'Venus Williams'},{id:83,frase:'La recuperaci\xf3n f\xedsica es inversi\xf3n central, no un lujo.',autor:'LeBron James'},{id:84,frase:'Pausar por agotamiento tambi\xe9n es una decisi\xf3n de alto rendimiento.',autor:'Simone Manuel'},{id:85,frase:'El descanso pesa tanto como los kil\xf3metros entrenados.',autor:'Eliud Kipchoge'},{id:86,frase:'Ajustar el entrenamiento respiratorio te permite competir pese a una condici\xf3n cr\xf3nica.',autor:'Jackie Joyner-Kersee'},{id:87,frase:'Ajustar cargas seg\xfan se\xf1ales objetivas de fatiga, no solo la sensaci\xf3n del d\xeda.',autor:'Katie Ledecky'},{id:88,frase:'Reeducar el cuerpo por completo tambi\xe9n es una forma de volver.',autor:'Bethany Hamilton'},{id:89,frase:'Cuidar la prevenci\xf3n de lesiones sostiene dos d\xe9cadas de exigencia f\xedsica.',autor:'Marta'},{id:90,frase:'Una mente regulada facilita superar obst\xe1culos que el cuerpo solo no resuelve.',autor:'Steffi Graf'},{id:91,frase:'Si no crees en ti mismo, nadie m\xe1s lo har\xe1 por ti.',autor:'Kobe Bryant'},{id:92,frase:'El talento gana partidos, pero la mentalidad decide los campeonatos.',autor:'Michael Jordan'},{id:93,frase:'No sabes lo que puedes lograr hasta que realmente lo intentas.',autor:'Michael Jordan'},{id:94,frase:'Un mal plan siempre es mejor que no tener ning\xfan plan.',autor:'Frank Marshall'},{id:95,frase:'El verdadero valor se ve en los momentos de desaf\xedo, no de comodidad.',autor:'Kobe Bryant'},{id:96,frase:'Reinventarte y vencer nuevos retos tambi\xe9n es una forma de \xe9xito.',autor:'Simone Biles'},{id:97,frase:'Cada derrota bien procesada deja algo constructivo para el pr\xf3ximo intento.',autor:'LeBron James'},{id:98,frase:'Los obst\xe1culos no te detienen; dejar de intentarlo s\xed.',autor:'Roger Federer'},{id:99,frase:'Hacer deporte es ense\xf1arle al cuerpo y a la mente a latir con salud.',autor:'An\xf3nimo (cultura deportiva)'},{id:100,frase:'Cu\xeddate como cuidas tu meta: los dos son el mismo proyecto.',autor:'Filosof\xeda JE Just Evolve'}]},1294,[]);
